import{c as l,$ as c,Q as a,j as h,m as o,h as s,ax as t,n as i,o as n,S as d}from"./chunks/framework.C5e1CAgN.js";const u="/_pr/417/assets/gsd-article-cover.D_24XU8v.png",y=JSON.parse('{"title":"When the Linter Met Its Match: Auditing a 48k-Star Project and Learning from the Diffs","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-04-06-how-we-helped-gsd.md","filePath":"case-studies/2026-04-06-how-we-helped-gsd.md","lastUpdated":null}'),g={name:"case-studies/2026-04-06-how-we-helped-gsd.md"};function p(m,e,f,b,A,w){const r=c("Mermaid");return a(),h("div",null,[e[5]||(e[5]=o('<h1 id="when-the-linter-met-its-match-auditing-a-48k-star-project-and-learning-from-the-diffs" tabindex="-1">When the Linter Met Its Match: Auditing a 48k-Star Project and Learning from the Diffs <a class="header-anchor" href="#when-the-linter-met-its-match-auditing-a-48k-star-project-and-learning-from-the-diffs" aria-label="Permalink to &quot;When the Linter Met Its Match: Auditing a 48k-Star Project and Learning from the Diffs&quot;">​</a></h1><p><img src="'+u+'" alt="Cover: A cracked magnifying glass with a seedling growing through it, a friendly robot and a human developer reviewing code together"></p><blockquote><p><strong>Disclosure</strong>: This article was drafted by Claude (Sonnet 4.6) based on session history from the engagement, then reviewed for factual accuracy against the GitHub record. The article describes Claude&#39;s own work auditing a third-party project using a tool (NLPM) built by the same author (<a href="https://github.com/xiaolai" target="_blank" rel="noreferrer">xiaolai</a>). Readers should weigh claims accordingly.</p></blockquote><h2 id="the-project-get-shit-done-gsd" tabindex="-1">The Project: get-shit-done (GSD) <a class="header-anchor" href="#the-project-get-shit-done-gsd" aria-label="Permalink to &quot;The Project: get-shit-done (GSD)&quot;">​</a></h2><p><a href="https://github.com/gsd-build/get-shit-done" target="_blank" rel="noreferrer"><code>gsd-build/get-shit-done</code></a> is a meta-prompting, context engineering, and spec-driven development system built for Claude Code by <a href="https://github.com/gsd-build" target="_blank" rel="noreferrer">TÂCHES</a>. As of early April 2026 it had <strong>48,053 GitHub stars</strong> and <strong>3,953 forks</strong>, making it one of the most-starred Claude Code plugin repositories in existence.</p><p>The project&#39;s description: &quot;A light-weight and powerful meta-prompting, context engineering and spec-driven development system for Claude Code.&quot;</p><p>In concrete terms, GSD is a framework of slash commands and subagents installed into Claude Code&#39;s <code>.claude/</code> directory. It gives Claude Code a structured workflow for software projects: planning phases, executing milestones, managing backlogs, profiling users, auditing security, generating documentation, and more. It ships with 21 agents and 59 commands — 80 natural language programming (NL) artifacts total. The commands include things like <code>/gsd:plan-phase</code>, <code>/gsd:execute-phase</code>, <code>/gsd:debug</code>, <code>/gsd:audit-milestone</code>, <code>/gsd:verify-work</code>, and <code>/gsd:autonomous</code>. The agents include specialists like <code>gsd-planner</code>, <code>gsd-executor</code>, <code>gsd-debugger</code>, <code>gsd-security-auditor</code>, and <code>gsd-user-profiler</code>.</p><p>The project uses JavaScript (CommonJS), enforces <code>node:test</code> (no Jest, no Mocha), and has CI with prompt injection scanning, base64 obfuscation scanning, and secret detection — an unusually security-conscious setup for an NL artifact project.</p><hr><h2 id="how-it-started" tabindex="-1">How It Started <a class="header-anchor" href="#how-it-started" aria-label="Permalink to &quot;How It Started&quot;">​</a></h2><p>On April 3, 2026, xaiolai dropped a single message:</p><blockquote><p><code>git@github.com:gsd-build/get-shit-done.git</code><br><code>clone it to ~/github/</code></p></blockquote><p>That was the entire brief — six words and a git URL, like handing someone a magnifying glass and pointing at a building. No instructions on what to look for, no scope set. The implication was clear enough.</p><p>The repo was cloned to <code>~/github/get-shit-done</code>. Then <a href="https://github.com/xiaolai/nlpm-for-claude" target="_blank" rel="noreferrer">NLPM</a> (Natural Language Programming Manager) was run against the entire repo.</p><hr><h2 id="the-tool-nlpm-—-natural-language-programming-manager" tabindex="-1">The Tool: NLPM — Natural Language Programming Manager <a class="header-anchor" href="#the-tool-nlpm-—-natural-language-programming-manager" aria-label="Permalink to &quot;The Tool: NLPM — Natural Language Programming Manager&quot;">​</a></h2><h3 id="design-goal" tabindex="-1">Design Goal <a class="header-anchor" href="#design-goal" aria-label="Permalink to &quot;Design Goal&quot;">​</a></h3><p>NLPM starts from a single premise: <strong>natural language artifacts are programs, and programs can be linted.</strong></p><p>Every Claude Code plugin is built from markdown files — commands, agents, skills, rules, hooks, CLAUDE.md. These files are not documentation. They are executable instructions that control AI behavior: what model to use, which tools to invoke, how to format output, when to block an action, what knowledge to load. A missing field in a command&#39;s YAML frontmatter is not a style issue — it is a registration failure. A vague instruction in an agent&#39;s body is not a readability concern — it is a nondeterministic behavior source.</p><p>Yet unlike JavaScript (ESLint), Python (ruff), or Rust (clippy), there was no linter for these artifacts. Authors wrote them by intuition, reviewed them by reading, and discovered defects the way you discover a hole in your umbrella — by getting rained on. NLPM exists to close that gap: apply the same systematic, repeatable, penalty-based quality analysis to NL artifacts that traditional linters apply to code.</p><h3 id="core-insight-natural-language-programs-have-deterministic-quality-properties" tabindex="-1">Core Insight: Natural Language Programs Have Deterministic Quality Properties <a class="header-anchor" href="#core-insight-natural-language-programs-have-deterministic-quality-properties" aria-label="Permalink to &quot;Core Insight: Natural Language Programs Have Deterministic Quality Properties&quot;">​</a></h3><p>The key insight behind NLPM is that while natural language is inherently fuzzy, the <em>structural properties</em> of NL programming artifacts are not. A poem can be vague and beautiful; a YAML frontmatter field is either present or it isn&#39;t. Consider:</p><ul><li>A command either has a <code>name:</code> field or it doesn&#39;t. Without it, the runtime can&#39;t register the command. This is binary.</li><li>An agent either declares its <code>tools:</code> list or it doesn&#39;t. Without it, tool access is undefined.</li><li>A rule file either has a bold imperative opening or it doesn&#39;t. Without it, Claude is more likely to ignore the rule.</li><li>A skill is either under 500 lines or it isn&#39;t. Over 500, it bloats the context window of every agent that loads it.</li></ul><p>These checks produce the same answer every time. The score is deterministic: same artifact, same penalties, same number. There is no subjective &quot;feel&quot; adjustment.</p><p>Where judgment <em>is</em> required — &quot;is this model tier appropriate for this task?&quot;, &quot;is this vague word usage legitimate in context?&quot; — NLPM labels the finding as <strong>(heuristic)</strong> in the report, so users know which assessments involved AI judgment versus mechanical pattern matching.</p><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>NLPM follows a strict <strong>commands orchestrate agents, agents use skills</strong> architecture:</p>',27)),(a(),s(d,null,{default:t(()=>[n(r,{id:"mermaid-100",class:"mermaid-diagram",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22User-Facing%20Commands%20(7)%22%0A%20%20%20%20%20%20%20%20ls%5B%22%2Fnlpm%3Als%22%5D%0A%20%20%20%20%20%20%20%20score%5B%22%2Fnlpm%3Ascore%22%5D%0A%20%20%20%20%20%20%20%20check%5B%22%2Fnlpm%3Acheck%22%5D%0A%20%20%20%20%20%20%20%20fix%5B%22%2Fnlpm%3Afix%22%5D%0A%20%20%20%20%20%20%20%20trend%5B%22%2Fnlpm%3Atrend%22%5D%0A%20%20%20%20%20%20%20%20test%5B%22%2Fnlpm%3Atest%22%5D%0A%20%20%20%20%20%20%20%20init%5B%22%2Fnlpm%3Ainit%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Agents%20(5)%22%0A%20%20%20%20%20%20%20%20scanner%5B%22scanner%3Cbr%2F%3E(haiku)%22%5D%0A%20%20%20%20%20%20%20%20scorer%5B%22scorer%3Cbr%2F%3E(sonnet)%22%5D%0A%20%20%20%20%20%20%20%20checker%5B%22checker%3Cbr%2F%3E(sonnet)%22%5D%0A%20%20%20%20%20%20%20%20vague%5B%22vague-scanner%3Cbr%2F%3E(haiku)%22%5D%0A%20%20%20%20%20%20%20%20tester%5B%22tester%3Cbr%2F%3E(sonnet)%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Skills%20(12)%22%0A%20%20%20%20%20%20%20%20core%5B%22Core%3A%20conventions%2C%20patterns%2C%3Cbr%2F%3Escoring%2C%20rules%2C%20testing%22%5D%0A%20%20%20%20%20%20%20%20writing%5B%22Writing%3A%20writing-skills%2C%3Cbr%2F%3Ewriting-agents%2C%20writing-rules%2C%3Cbr%2F%3Ewriting-prompts%2C%20writing-hooks%2C%3Cbr%2F%3Ewriting-plugins%2C%20orchestration%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20ls%20--%3E%20scanner%0A%20%20%20%20score%20--%3E%20scorer%0A%20%20%20%20score%20--%3E%20vague%0A%20%20%20%20check%20--%3E%20checker%0A%20%20%20%20fix%20--%3E%20scorer%0A%20%20%20%20trend%20--%3E%20scorer%0A%20%20%20%20trend%20--%3E%20vague%0A%20%20%20%20test%20--%3E%20tester%0A%0A%20%20%20%20scanner%20--%3E%20core%0A%20%20%20%20scorer%20--%3E%20core%0A%20%20%20%20checker%20--%3E%20core%0A%20%20%20%20tester%20--%3E%20core%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=o('<p>Each layer has a distinct responsibility:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Responsibility</th><th>Example</th></tr></thead><tbody><tr><td><strong>Commands</strong></td><td>Parse user input, dispatch agents, format final output</td><td><code>/nlpm:score agents/</code> parses the path, dispatches scorer + vague-scanner in parallel, merges results into a report</td></tr><tr><td><strong>Agents</strong></td><td>Perform analysis, apply judgment, produce structured findings</td><td>The scorer reads each file, applies the penalty rubric, and outputs a score table</td></tr><tr><td><strong>Skills</strong></td><td>Provide reference knowledge agents need to do their job</td><td>The scoring skill contains penalty tables; the conventions skill defines valid YAML schemas</td></tr></tbody></table><p>Commands never do analysis themselves. Agents never interact with the user. Skills are reference material, never imperative instructions. The separation is strict.</p><h3 id="the-50-rules-and-scoring" tabindex="-1">The 50 Rules and Scoring <a class="header-anchor" href="#the-50-rules-and-scoring" aria-label="Permalink to &quot;The 50 Rules and Scoring&quot;">​</a></h3><p>NLPM enforces 50 rules across 10 categories (Universal, Skills, Agents, Commands, Shared Partials, Rules, Hooks, CLAUDE.md, Prompts, Orchestration, Plugins). Each rule maps to a penalty in the scoring rubric. The scoring formula is simple: start at 100, subtract penalties for every issue found. No bonuses — like a building inspection, the score reflects what&#39;s not up to code, not how lovely the architecture looks.</p><table tabindex="0"><thead><tr><th>Range</th><th>Label</th><th>Meaning</th></tr></thead><tbody><tr><td>90-100</td><td>Excellent</td><td>Production-ready</td></tr><tr><td>80-89</td><td>Good</td><td>Minor gaps</td></tr><tr><td>70-79</td><td>Adequate</td><td>Meets threshold, should improve</td></tr><tr><td>60-69</td><td>Weak</td><td>Below threshold</td></tr><tr><td>&lt;60</td><td>Rewrite</td><td>Fundamental problems</td></tr></tbody></table><p>Default pass threshold: 70. Where judgment is required (e.g., &quot;is this model tier appropriate?&quot;), NLPM labels the finding as <strong>(heuristic)</strong> so users know which assessments involved AI reasoning versus mechanical checks.</p><h3 id="how-a-score-run-works" tabindex="-1">How a Score Run Works <a class="header-anchor" href="#how-a-score-run-works" aria-label="Permalink to &quot;How a Score Run Works&quot;">​</a></h3><ol><li><strong>Discovery</strong> (haiku): Glob for artifact patterns, classify by path, count lines.</li><li><strong>Parallel scoring</strong>: The <strong>vague-scanner</strong> (haiku) counts flagged words mechanically; the <strong>scorer</strong> (sonnet) applies the full penalty rubric with heuristic judgment where needed.</li><li><strong>Merge</strong>: Deterministic word counts from the vague-scanner override the scorer&#39;s own detection when they disagree.</li><li><strong>Report</strong>: Per-file scores, ranked issue list, overall average.</li></ol><p>The process is read-only — NLPM never modifies artifacts during scoring. A separate <code>/nlpm:fix</code> command handles repairs, and only mechanical fixes are applied automatically; judgment calls require user approval.</p><p>NLPM also provides cross-component checking (<code>/nlpm:check</code>) for reference integrity, orphan detection, and behavioral contradictions — and an NL-TDD system (<code>/nlpm:test</code>) for spec-driven development of NL artifacts. See the <a href="https://github.com/xiaolai/nlpm-for-claude" target="_blank" rel="noreferrer">NLPM repository</a> for full documentation.</p><hr><h2 id="the-audit-80-files-scored-in-parallel" tabindex="-1">The Audit: 80 Files Scored in Parallel <a class="header-anchor" href="#the-audit-80-files-scored-in-parallel" aria-label="Permalink to &quot;The Audit: 80 Files Scored in Parallel&quot;">​</a></h2><p>NLPM (<code>nlpm:score</code>) was invoked with the repo root as argument. It discovered all 80 NL artifacts — 21 agents and 59 commands — and scored them in 8 parallel batches. The scoring criteria applied penalties for: missing/malformed YAML frontmatter, no output format specification, hollow delegation patterns, missing examples, vague qualifiers, and structural defects.</p><h3 id="overall-score-74-100-—-adequate" tabindex="-1">Overall Score: 74/100 — ADEQUATE <a class="header-anchor" href="#overall-score-74-100-—-adequate" aria-label="Permalink to &quot;Overall Score: 74/100 — ADEQUATE&quot;">​</a></h3><p>The results by category:</p><table tabindex="0"><thead><tr><th>Type</th><th>Count</th><th>Avg Score</th><th>Min</th><th>Max</th></tr></thead><tbody><tr><td>Agent</td><td>21</td><td>79.2</td><td>66</td><td>90</td></tr><tr><td>Command</td><td>59</td><td>72.4</td><td>48</td><td>86</td></tr></tbody></table><p>Score distribution:</p>',18)),(a(),s(d,null,{default:t(()=>[n(r,{id:"mermaid-342",class:"mermaid-diagram",graph:"pie%20title%20GSD%20Score%20Distribution%20(80%20files)%0A%20%20%20%20%2290-100%20Excellent%22%20%3A%201%0A%20%20%20%20%2280-89%20Good%22%20%3A%2024%0A%20%20%20%20%2270-79%20Adequate%22%20%3A%2032%0A%20%20%20%20%2260-69%20Weak%22%20%3A%2019%0A%20%20%20%20%22Below%2060%20Rewrite%22%20%3A%204%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=o('<p>The valedictorian: <code>gsd-nyquist-auditor.md</code> at 90/100 — the only file to crack Excellent. The one that needed the most love: <code>commands/gsd/workstreams.md</code> at 48/100, missing its own name.</p><h3 id="top-issues-found" tabindex="-1">Top Issues Found <a class="header-anchor" href="#top-issues-found" aria-label="Permalink to &quot;Top Issues Found&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>File</th><th>Issue</th><th>Score Impact</th></tr></thead><tbody><tr><td>P0</td><td><code>commands/gsd/workstreams.md</code></td><td>Missing <code>name:</code> field — non-canonical; may fall back to filename in some runtimes but breaks cross-runtime portability</td><td>-15</td></tr><tr><td>P0</td><td><code>commands/gsd/reapply-patches.md</code></td><td>Missing <code>name:</code> field + <code>allowed-tools</code> as scalar string instead of YAML list</td><td>-15</td></tr><tr><td>P0*</td><td><code>agents/gsd-ui-auditor.md</code></td><td><code>tools:</code> is a comma-separated scalar string, not a YAML list — schema portability concern</td><td>-10</td></tr><tr><td>P0*</td><td><code>agents/gsd-ui-checker.md</code></td><td>Same — <code>tools:</code> scalar string</td><td>-10</td></tr><tr><td>P0*</td><td><code>agents/gsd-verifier.md</code></td><td>Same — <code>tools:</code> scalar string</td><td>-10</td></tr></tbody></table><p>* <em>Note: scalar-string <code>tools:</code> fields (e.g., <code>tools: Read, Glob, Grep</code>) are accepted by Claude Code&#39;s parser and by GSD&#39;s own code. NLPM originally flagged these as defects, but this was an NLPM convention preference, not a runtime bug. NLPM v0.7.0 was subsequently updated to accept both formats. These items were correctly excluded from the PRs submitted.</em> | P0 | <code>commands/gsd/review-backlog.md</code> | Step 3 uses <code>AskUserQuestion</code> but it&#39;s not in <code>allowed-tools</code> — runtime failure | -10 | | P0 | <code>agents/gsd-user-profiler.md</code> | <code>@</code> import path conflicts with <code>&lt;step&gt;</code> path — profiling rubric may silently fail to load | -10 | | P1 | <code>commands/gsd/cleanup.md</code> | Missing <code>allowed-tools</code> entirely — unrestricted tool access | -5 | | P1 | <code>commands/gsd/help.md</code> | Same | -5 | | P1 | <code>commands/gsd/join-discord.md</code> | Same | -5 |</p><p>Beyond the critical P0/P1 category:</p><ul><li><strong>78/80 files</strong> had no <code>&lt;examples&gt;</code> block at all — the single highest-score improvement available (+10 pts each)</li><li><strong>40/59 commands</strong> used hollow wrapper patterns (100% delegation with zero inline logic)</li><li><strong>35/59 commands</strong> had no output format specification</li><li><code>gsd-debugger.md</code> was 1,380 lines with no modularization — loading philosophy and techniques on every invocation regardless of debug mode</li><li><strong>21/21 agents</strong> had no <code>&lt;injection_contract&gt;</code> documenting orchestrator-injected variables like <code>$PHASE_DIR</code>, <code>$PADDED_PHASE</code>, <code>$PHASE_NUM</code></li><li><strong>4 agents</strong> referenced MCP tools (<code>mcp__context7__*</code>, <code>mcp__exa__*</code>, <code>mcp__firecrawl__*</code>) with no fallback if those servers were unavailable</li><li><code>gsd-roadmapper.md</code> had overlapping granularity ranges: Coarse 3-5, Standard 5-8, Fine 8-12 — with 5 and 8 each appearing in two ranges, making the rule non-deterministic</li></ul><hr><h2 id="the-plan-24-prs" tabindex="-1">The Plan: 24 PRs <a class="header-anchor" href="#the-plan-24-prs" aria-label="Permalink to &quot;The Plan: 24 PRs&quot;">​</a></h2><p>After reviewing the repo&#39;s governance structure (CONTRIBUTING.md, issue templates, PR template, CI workflows), 24 PR proposals were drafted.</p>',9)),(a(),s(d,null,{default:t(()=>[n(r,{id:"mermaid-489",class:"mermaid-diagram",graph:"graph%20LR%0A%20%20%20%20subgraph%20P0%5B%22P0%3A%20Registration-breaking%22%5D%0A%20%20%20%20%20%20%20%20p0%5B%224%20PRs%3A%20missing%20name%20field%2C%3Cbr%2F%3Emissing%20allowed-tools%2C%3Cbr%2F%3Econflicting%20paths%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20P1%5B%22P1%3A%20Highest%20score%20impact%22%5D%0A%20%20%20%20%20%20%20%20p1%5B%224%20PRs%3A%20add%20examples%3Cbr%2F%3Eto%20all%2080%20files%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20P2%5B%22P2%3A%20Correctness%22%5D%0A%20%20%20%20%20%20%20%20p2%5B%227%20PRs%3A%20runtime%20failures%2C%3Cbr%2F%3Econtradictions%2C%20MCP%20fallbacks%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20P3%5B%22P3%3A%20Quality%22%5D%0A%20%20%20%20%20%20%20%20p3%5B%229%20PRs%3A%20dead%20code%2C%20modularize%3Cbr%2F%3Edebugger%2C%20injection%20contracts%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20P0%20--%3E%7Csubmitted%7C%20P1%0A%20%20%20%20P1%20--%3E%7Cdeferred%7C%20P2%0A%20%20%20%20P2%20--%3E%7Cdeferred%7C%20P3%0A%0A%20%20%20%20style%20p0%20fill%3A%23d73a4a%2Ccolor%3A%23fff%0A%20%20%20%20style%20p1%20fill%3A%23e99d42%2Ccolor%3A%23fff%0A%20%20%20%20style%20p2%20fill%3A%230075ca%2Ccolor%3A%23fff%0A%20%20%20%20style%20p3%20fill%3A%237057ff%2Ccolor%3A%23fff%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[i(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=o('<p>They were grouped by priority:</p><p><strong>P0 — Registration-breaking (PRs 1, 3, 4, 5):</strong> Commands and agents that silently fail to load or execute.</p><p><strong>P1 — Highest score impact (PRs 7, 8, 9, 10):</strong> Adding <code>&lt;examples&gt;</code> blocks to all 80 files — the single change that would move the overall average from ADEQUATE to GOOD.</p><p><strong>P2 — Correctness (PRs 2, 6, 11, 17, 20, 21, 22):</strong> Runtime failures, contradictions, missing fallbacks, false negatives in the auth checker.</p><p><strong>P3 — Quality (PRs 12-16, 18, 19, 23, 24):</strong> Dead code cleanup, modularization of the 1,380-line debugger, documenting injection contracts, replacing vague qualifiers with deterministic criteria.</p><hr><h2 id="the-decision-focus-on-the-p0s" tabindex="-1">The Decision: Focus on the P0s <a class="header-anchor" href="#the-decision-focus-on-the-p0s" aria-label="Permalink to &quot;The Decision: Focus on the P0s&quot;">​</a></h2><p>xaiolai reviewed the list and made a key scoping decision:</p><blockquote><p>&quot;ignore all scalar string&quot; (the P0 agents with tools as strings)<br> &quot;OK, only propose pr for these issues.&quot;<br> &quot;go ahead.&quot;</p></blockquote><p>This narrowed the scope to the 5 most critical issues — the ones most likely to cause real user-facing failures. The reasoning: scalar-string <code>tools:</code> fields were in agents (which might work anyway depending on the parser&#39;s tolerance), while missing <code>name:</code> fields and missing <code>AskUserQuestion</code> in <code>allowed-tools</code> were definite runtime failures.</p><hr><h2 id="first-attempt-parallel-agents-—-a-mess" tabindex="-1">First Attempt: Parallel Agents — A Mess <a class="header-anchor" href="#first-attempt-parallel-agents-—-a-mess" aria-label="Permalink to &quot;First Attempt: Parallel Agents — A Mess&quot;">​</a></h2>',12)),(a(),s(d,null,{default:t(()=>[n(r,{id:"mermaid-524",class:"mermaid-diagram",graph:"sequenceDiagram%0A%20%20%20%20participant%20C%20as%20Command%0A%20%20%20%20participant%20A1%20as%20Agent%201%0A%20%20%20%20participant%20A2%20as%20Agent%202%0A%20%20%20%20participant%20A3%20as%20Agent%203%0A%20%20%20%20participant%20Git%20as%20Git%20Worktree%0A%0A%20%20%20%20C-%3E%3EA1%3A%20PR%20%231%20(name%3A%20field)%0A%20%20%20%20C-%3E%3EA2%3A%20PR%20%232%20(AskUserQuestion)%0A%20%20%20%20C-%3E%3EA3%3A%20PR%20%233%20(path%20refs)%0A%20%20%20%20A1-%3E%3EGit%3A%20create%20branch%2C%20commit%0A%20%20%20%20A2-%3E%3EGit%3A%20create%20branch%2C%20commit%0A%20%20%20%20A3-%3E%3EGit%3A%20create%20branch%2C%20commit%0A%20%20%20%20Note%20over%20Git%3A%20Crossed%20wires%20%E2%80%94%3Cbr%2F%3Ecommits%20on%20wrong%20branches%2C%3Cbr%2F%3Estash%20entries%20interleaved%0A%20%20%20%20A2--xGit%3A%20API%20error%0A%20%20%20%20Git--%3E%3EC%3A%20Inconsistent%20state%0A%20%20%20%20C-%3E%3EGit%3A%20git%20reset%20--hard%20origin%2Fmain%0A%20%20%20%20Note%20over%20C%2CGit%3A%20Clean%20slate%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[i(" Loading... ",-1)])]),_:1})),e[9]||(e[9]=o(`<p>The first attempt used 5 parallel subagents, each assigned to one PR. What followed was the git equivalent of five chefs sharing one cutting board — commits ended up on wrong branches, stash entries interleaved, and the whole kitchen needed hosing down. Hard reset, clean slate, lesson learned.</p><hr><h2 id="second-attempt-sequential-direct-—-clean" tabindex="-1">Second Attempt: Sequential, Direct — Clean <a class="header-anchor" href="#second-attempt-sequential-direct-—-clean" aria-label="Permalink to &quot;Second Attempt: Sequential, Direct — Clean&quot;">​</a></h2><p>Each PR was executed directly in sequence: read target file, understand existing format, make minimal diff, commit, push to fork (<a href="https://github.com/xiaolai/get-shit-done" target="_blank" rel="noreferrer"><code>xiaolai/get-shit-done</code></a>), create PR.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1573" target="_blank" rel="noreferrer">PR #1573</a></strong> — <code>fix: add missing name field to workstreams and reapply-patches commands</code></p><p>Added <code>name: gsd:workstreams</code> and <code>name: gsd:reapply-patches</code> to match the naming convention of all 57 other command files. Without <code>name:</code>, some Claude Code runtimes may fall back to the filename, but the explicit field ensures consistent registration across all environments — and every other command in the repo declared it.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1574" target="_blank" rel="noreferrer">PR #1574</a></strong> — <code>fix: add AskUserQuestion to review-backlog allowed-tools</code></p><p><code>review-backlog.md</code> Step 3 explicitly calls for <code>AskUserQuestion</code> to present each backlog item to the user. But the tool wasn&#39;t listed in <code>allowed-tools</code>. The command would fail at exactly the moment it tried to prompt the user.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1575" target="_blank" rel="noreferrer">PR #1575</a></strong> — <code>fix: resolve conflicting path references in gsd-user-profiler</code></p><p>The agent&#39;s <code>&lt;reference&gt;</code> block used <code>@get-shit-done/references/user-profiling.md</code>. Its <code>&lt;step name=&quot;load_rubric&quot;&gt;</code> used <code>get-shit-done/references/user-profiling.md</code>. Neither matched the repo convention (<code>@~/.claude/get-shit-done/...</code>). If the runner couldn&#39;t resolve either format, the user profiling rubric would silently fail to load — the profiler would run with no actual rubric backing it.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1576" target="_blank" rel="noreferrer">PR #1576</a></strong> — <code>fix: add missing allowed-tools to 4 commands</code></p><p>Four commands (<code>cleanup.md</code>, <code>help.md</code>, <code>join-discord.md</code>, <code>workstreams.md</code>) had no <code>allowed-tools</code> field at all. Every other command in the repo declared an explicit tool set. Omitting the field grants unrestricted tool access — a principle-of-least-privilege violation. Each got a minimal, appropriate tool list: <code>[Read, Bash]</code> for commands that only delegate to <code>node &quot;$GSD_TOOLS&quot;</code>, <code>[]</code> for commands that produce pure text output.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1577" target="_blank" rel="noreferrer">PR #1577</a></strong> — <code>fix: remove empty stub step in reapply-patches</code></p><p>Step 5 of <code>reapply-patches.md</code> contained nothing but two bash comments:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># The manifest will be regenerated on next /gsd:update</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># For now, just note which files were modified</span></span></code></pre></div><p>The comments themselves admitted no work was being done. The step was removed and the remaining steps renumbered.</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/issues/1578" target="_blank" rel="noreferrer">Issue #1578</a></strong> — tracking issue documenting all 9 critical defects, the full audit methodology, and all 5 PRs.</p><p>All 5 PRs were submitted within approximately 15 minutes of the clean-slate restart (06:20 to 06:35 UTC, per GitHub timestamps). Sometimes the sequel is shorter than the blooper reel.</p><hr><h2 id="the-maintainer-s-response" tabindex="-1">The Maintainer&#39;s Response <a class="header-anchor" href="#the-maintainer-s-response" aria-label="Permalink to &quot;The Maintainer&#39;s Response&quot;">​</a></h2><p>The maintainer (<a href="https://github.com/trek-e" target="_blank" rel="noreferrer"><code>trek-e</code></a>, Tom Boucher) did not merge the PRs individually. Instead, he reviewed all five, agreed with all the diagnoses, and implemented a single commit (<a href="https://github.com/gsd-build/get-shit-done/commit/08f59fabb4e89e42a28a852adb2073ebbff953d6" target="_blank" rel="noreferrer"><code>08f59fa</code></a>) that incorporated all the fixes simultaneously. The commit message confirmed acknowledgment:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fix(nlpm): resolve 5 critical defects from NLPM audit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- Add missing name: field to workstreams and reapply-patches commands</span></span>
<span class="line"><span>- Add AskUserQuestion to review-backlog allowed-tools</span></span>
<span class="line"><span>- Fix conflicting path references in gsd-user-profiler (use ~/.claude/get-shit-done/... convention)</span></span>
<span class="line"><span>- Add allowed-tools to cleanup, help, and join-discord commands</span></span>
<span class="line"><span>- Remove empty stub Step 5 from reapply-patches (dead bash comment block)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Closes #1578</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Co-Authored-By: Claude Sonnet 4.6 &lt;noreply@anthropic.com&gt;</span></span></code></pre></div><p>Notably: the <code>Co-Authored-By</code> line credits <code>Claude Sonnet 4.6</code> directly — a small line in a commit message, but a quiet acknowledgment that the diagnosis came from somewhere worth naming. All 5 PRs were closed as superseded by this commit, not merged separately.</p><hr><h2 id="the-follow-up-pr-1638" tabindex="-1">The Follow-Up: PR #1638 <a class="header-anchor" href="#the-follow-up-pr-1638" aria-label="Permalink to &quot;The Follow-Up: PR #1638&quot;">​</a></h2><p>In the <a href="https://github.com/gsd-build/get-shit-done/pull/1576" target="_blank" rel="noreferrer">#1576</a> review, the maintainer noted a nuance: the locally-merged version had added <code>Write</code> to <code>workstreams.md</code>&#39;s allowed-tools, but the PR&#39;s proposed set of <code>[Read, Bash]</code> was actually tighter and more accurate. The command only delegates to <code>node &quot;$GSD_TOOLS&quot;</code> via Bash — it never writes files directly.</p><p>A new issue (<a href="https://github.com/gsd-build/get-shit-done/issues/1637" target="_blank" rel="noreferrer">#1637</a>) was opened to document this. <a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">PR #1638</a> followed:</p><p><strong><a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">PR #1638</a></strong> — <code>fix: remove unnecessary Write from workstreams allowed-tools</code></p><p>Tightened <code>[Read, Write, Bash]</code> to <code>[Read, Bash]</code>. The maintainer had inadvertently introduced a broader-than-necessary tool surface in his consolidation commit.</p><p>However, <a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">PR #1638</a> was closed as a duplicate — the maintainer (or another contributor) had already submitted <a href="https://github.com/gsd-build/get-shit-done/pull/1642" target="_blank" rel="noreferrer">PR #1642</a> with the same fix, which was merged at 11:24 UTC on April 4. The issue was resolved, just not via our PR. In open source, it&#39;s perfectly fine to arrive second with the right answer — what matters is that the answer arrives.</p><p>Polite replies were posted to all 5 original PRs: acknowledging the superseding commit, thanking for the review, and noting the outstanding item from <a href="https://github.com/gsd-build/get-shit-done/pull/1576" target="_blank" rel="noreferrer">#1576</a>.</p><hr><h2 id="what-the-audit-revealed-about-nl-artifact-quality-at-scale" tabindex="-1">What the Audit Revealed About NL Artifact Quality at Scale <a class="header-anchor" href="#what-the-audit-revealed-about-nl-artifact-quality-at-scale" aria-label="Permalink to &quot;What the Audit Revealed About NL Artifact Quality at Scale&quot;">​</a></h2><p><strong>A fairness note</strong>: GSD is a fast-moving project maintained by a small team shipping rapidly across multiple runtime contexts. The defects found were the kind that accumulate naturally in any large NL artifact codebase under active development — they reflect the pace of iteration, not a lack of care. The maintainer&#39;s immediate, thorough response to the audit confirms the project&#39;s quality orientation. A 74/100 score passes NLPM&#39;s default threshold (70) and falls in the &quot;adequate&quot; band — functional, with room to improve.</p><p>The GSD audit exposed patterns that are likely universal in large NL artifact repos:</p><p><strong>Structural defects are rare but critical.</strong> Only 5 files out of 80 had true registration-breaking issues — like a bridge with 80 bolts where 5 are missing. The bridge might hold, but you&#39;d rather find out from an inspector than from the traffic. Users encountering <code>workstreams.md</code> or <code>reapply-patches.md</code> would see command-not-found errors with no indication of why.</p><p><strong>Missing examples are universal.</strong> 78 of 80 files had zero <code>&lt;examples&gt;</code> blocks. This is the highest-leverage improvement available — each added example block is worth +10 points — but also the one requiring the most editorial work. There is no mechanical fix.</p><p><strong>Hollow delegation is rampant.</strong> 40 of 59 commands were single-line delegations — like a receptionist who only says &quot;ask the person down the hall.&quot; The command file tells you nothing about what actually happens; you have to follow the import chain to find the real logic.</p><p><strong>Least-privilege defaults are absent.</strong> 4 commands had no <code>allowed-tools</code> field. The default behavior (unrestricted access) is exactly wrong for a security-conscious repo that runs prompt injection scans on every PR.</p><p><strong>Injection contracts are undocumented.</strong> Every agent uses variables injected by the orchestrator (<code>$PHASE_DIR</code>, <code>$PADDED_PHASE</code>, <code>$PHASE_NUM</code>). None of them document the contract. A developer reading an agent to understand what it needs cannot learn that from the file itself — they have to find the orchestrator and reverse-engineer the injection.</p><p><strong>MCP fallbacks are absent.</strong> 4 agents reference external MCP tools without any fallback for when those servers are unavailable. In any environment without those servers, the agents silently degrade.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2>`,43)),(a(),s(d,null,{default:t(()=>[n(r,{id:"mermaid-640",class:"mermaid-diagram",graph:"gantt%0A%20%20%20%20title%20GSD%20Audit%20Timeline%20(UTC)%0A%20%20%20%20dateFormat%20YYYY-MM-DD%20HH%3Amm%0A%20%20%20%20axisFormat%20%25H%3A%25M%0A%0A%20%20%20%20section%20April%203%20%E2%80%94%20Audit%0A%20%20%20%20Clone%20repo%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20clone%2C%202026-04-03%2005%3A01%2C%202m%0A%20%20%20%20nlpm%20score%20(8%20parallel%20agents)%20%20%20%20%20%20%3Adone%2C%20score%2C%202026-04-03%2005%3A18%2C%208m%0A%20%20%20%20Report%20generated%2074%20of%20100%20%20%20%20%20%20%20%20%20%20%3Amilestone%2C%20report%2C%202026-04-03%2005%3A26%2C%200m%0A%20%20%20%20Governance%20review%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20gov%2C%202026-04-03%2005%3A26%2C%204m%0A%20%20%20%2024%20PR%20proposals%20drafted%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20plan%2C%202026-04-03%2005%3A30%2C%206m%0A%20%20%20%20Fork%20created%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20fork%2C%202026-04-03%2005%3A42%2C%202m%0A%0A%20%20%20%20section%20April%203%20%E2%80%94%20Implementation%0A%20%20%20%20Parallel%20agents%20FAILED%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Acrit%2C%20para%2C%202026-04-03%2005%3A44%2C%2036m%0A%20%20%20%20Clean%20slate%20restart%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Amilestone%2C%20reset%2C%202026-04-03%2006%3A20%2C%200m%0A%20%20%20%20Sequential%20PRs%201573%20to%201577%20%20%20%20%20%20%20%20%20%3Adone%2C%20prs%2C%202026-04-03%2006%3A20%2C%2015m%0A%20%20%20%20Tracking%20issue%201578%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Amilestone%2C%20issue%2C%202026-04-03%2006%3A35%2C%200m%0A%0A%20%20%20%20section%20April%203%20%E2%80%94%20Maintainer%0A%20%20%20%20Maintainer%20commits%2008f59fa%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20merge%2C%202026-04-03%2015%3A12%2C%205m%0A%0A%20%20%20%20section%20April%204%20%E2%80%94%20Follow-up%0A%20%20%20%20Discover%20PRs%20superseded%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20disc%2C%202026-04-04%2005%3A28%2C%208m%0A%20%20%20%20Issue%201637%20and%20PR%201638%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20followup%2C%202026-04-04%2005%3A35%2C%204m%0A%20%20%20%20Replies%20posted%20to%20all%20PRs%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%20replies%2C%202026-04-04%2005%3A39%2C%201m%0A"})]),fallback:t(()=>[...e[4]||(e[4]=[i(" Loading... ",-1)])]),_:1})),e[10]||(e[10]=o('<p>Key timestamps with links:</p><ul><li><strong>06:31-06:35 UTC</strong>: PRs <a href="https://github.com/gsd-build/get-shit-done/pull/1573" target="_blank" rel="noreferrer">#1573</a>-<a href="https://github.com/gsd-build/get-shit-done/pull/1577" target="_blank" rel="noreferrer">#1577</a> and issue <a href="https://github.com/gsd-build/get-shit-done/issues/1578" target="_blank" rel="noreferrer">#1578</a> created</li><li><strong>15:12 UTC</strong>: Maintainer commits <a href="https://github.com/gsd-build/get-shit-done/commit/08f59fabb4e89e42a28a852adb2073ebbff953d6" target="_blank" rel="noreferrer"><code>08f59fa</code></a> — all fixes applied</li><li><strong>April 4, 05:36 UTC</strong>: <a href="https://github.com/gsd-build/get-shit-done/issues/1637" target="_blank" rel="noreferrer">Issue #1637</a> and <a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">PR #1638</a> submitted</li></ul><hr><h2 id="key-technical-decisions" tabindex="-1">Key Technical Decisions <a class="header-anchor" href="#key-technical-decisions" aria-label="Permalink to &quot;Key Technical Decisions&quot;">​</a></h2><p><strong>Decision: Focus only on P0 structural failures, not the full 24-PR plan.</strong></p><p>Rationale: The scalar-string <code>tools:</code> fields in 3 agents might be tolerated by lenient YAML parsers — the real failures were guaranteed to be the missing <code>name:</code> fields and the <code>AskUserQuestion</code> omission. Limiting scope to 5 PRs made the contribution manageable and review-friendly, given the repo&#39;s <code>CODEOWNERS</code> requiring maintainer sign-off on everything.</p><p><strong>Decision: Sequential implementation after parallel agent failure.</strong></p><p>Rationale: The parallel approach created a corrupted state (branches with mixed commits, stash entries from multiple agents). The cleanup and redo was faster than trying to untangle the mess. The lesson: for changes that touch the same files across branches, parallel agents create race conditions on the working tree.</p><p><strong>Decision: Post a tracking issue alongside the PRs.</strong></p><p>Rationale: The maintainer needed context. Five small PRs with no explanation of the audit methodology would look arbitrary. The tracking issue <a href="https://github.com/gsd-build/get-shit-done/issues/1578" target="_blank" rel="noreferrer">#1578</a> gave the full picture — what tool was used, what methodology, all 9 critical issues, a priority matrix — and let the maintainer make informed decisions about which PRs to prioritize and which to defer.</p><p><strong>Decision: Follow up with <a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">PR #1638</a> based on maintainer feedback.</strong></p><p>Rationale: The maintainer caught a real nuance in his own consolidation commit — he&#39;d added <code>Write</code> unnecessarily. Accepting that feedback and submitting the correction demonstrated good-faith collaboration and produced a strictly better outcome than either the original proposal or the maintainer&#39;s own fix.</p><hr><h2 id="what-was-built-vs-what-was-fixed" tabindex="-1">What Was Built vs. What Was Fixed <a class="header-anchor" href="#what-was-built-vs-what-was-fixed" aria-label="Permalink to &quot;What Was Built vs. What Was Fixed&quot;">​</a></h2><p>This engagement was not about building new features. It was about systematic quality assurance of an existing NL artifact ecosystem using NLPM — a framework for treating natural language programming artifacts (prompts, agents, commands, skills, rules) as first-class software that can be scored, audited, and improved with the same rigor as code.</p><p>What was delivered:</p><ul><li>A complete NLPM audit report of 80 files with per-file scores, issue lists, and a priority matrix</li><li>5 structural fix PRs submitted (<a href="https://github.com/gsd-build/get-shit-done/pull/1573" target="_blank" rel="noreferrer">#1573</a>-<a href="https://github.com/gsd-build/get-shit-done/pull/1577" target="_blank" rel="noreferrer">#1577</a>), all diagnoses confirmed by the maintainer</li><li>1 follow-up PR (<a href="https://github.com/gsd-build/get-shit-done/pull/1638" target="_blank" rel="noreferrer">#1638</a>), closed as duplicate — the same fix landed via <a href="https://github.com/gsd-build/get-shit-done/pull/1642" target="_blank" rel="noreferrer">#1642</a></li><li>A tracking issue (<a href="https://github.com/gsd-build/get-shit-done/issues/1578" target="_blank" rel="noreferrer">#1578</a>) documenting the full audit</li><li>All 5 original fixes incorporated into main via the maintainer&#39;s consolidation commit, credited to Claude Code</li></ul><p>What was surfaced but deferred:</p><ul><li>19 more PRs addressing quality, documentation, and refactoring concerns</li><li>The universal absence of <code>&lt;examples&gt;</code> blocks (the highest-ROI improvement)</li><li>Modularization of <code>gsd-debugger.md</code> (1,380 lines)</li><li>Injection contracts and structured trigger blocks for all 21 agents</li><li>MCP fallback chains for research agents</li></ul><p>The deferred work represents the delta between &quot;adequate&quot; (74/100) and &quot;excellent&quot; (90+). The critical fixes delivered brought the repo from having silent runtime failures to having clean registration, correct tool access declarations, and consistent path resolution.</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p>This engagement validated NLPM against one project. It does not prove the methodology generalizes across all NL artifact codebases. Specific caveats:</p><ul><li><strong>No runtime reproduction</strong>: The structural defects (missing <code>name:</code>, missing <code>allowed-tools</code>) were identified by static analysis. We did not reproduce runtime failures in GSD&#39;s actual execution environment. Claude Code may tolerate some of these through fallback behavior.</li><li><strong>NLPM&#39;s rules are opinionated</strong>: Several findings (hollow delegation, missing examples, undocumented injection contracts) reflect NLPM&#39;s quality model, not universal standards. Reasonable developers can disagree on whether these are defects or acceptable trade-offs for rapid iteration.</li><li><strong>No post-fix scoring</strong>: The repo was not re-scored after the fixes landed. We cannot quantify the score improvement.</li><li><strong>Sample size of one</strong>: Patterns identified (&quot;missing examples are universal&quot;, &quot;least-privilege defaults are absent&quot;) are observed in one project. They may not generalize.</li></ul><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>GSD is one of the most actively maintained Claude Code frameworks in the ecosystem. The five structural fixes addressed real consistency issues in a codebase that 48k users rely on. Whether these would have manifested as user-facing failures depends on the specific runtime and parser — but the maintainer reviewed each diagnosis, agreed with all five, and incorporated them into the project.</p><p>The maintainer&#39;s commit message credited <code>Claude Sonnet 4.6</code> as co-author — an acknowledgment that the contribution was treated as substantive, not noise.</p><p>For NLPM, the experience was a mirror as much as a microscope. The tool found genuine structural defects (confirmed by the maintainer), but also flagged convention preferences as bugs (scalar-string <code>tools:</code> fields). That false-positive led directly to NLPM v0.7.0 updating its own rules to accept both formats. There is a gentle irony in a linter that goes out to audit someone else&#39;s code and comes home with homework of its own — but perhaps that is exactly how tools ought to grow.</p>',29))])}const v=l(g,[["render",p]]);export{y as __pageData,v as default};
